import random
from datetime import date
from backend.algorithm.rotation_engine import generate_rotation
from backend.models.match import Match, Squad
from backend.models.player import GKTier
from backend.models.rotation import Position
from tests.conftest import make_player

violations = {'position': 0, 'sub_limit': 0, 'other': 0}
for seed in range\(500\):
    random.seed\(seed\)
    squad = Squad\(players=[
        make_player\('Preferred', GKTier.PREFERRED\),
        *[make_player\(f'P{i}'\) for i in range\(2, 10\)],
    ]\)
    plan = generate_rotation\(squad, Match\(date=date\(2026,3,23\)\)\)

    pos_violation = False
    for player in squad.available:
        raw = {pos for slot in plan.slots for pos, p in slot.lineup.items\(\) if p is player}
        norm = {'MID' if pos in \(Position.MID1, Position.MID2\) else pos.value for pos in raw}
        if len\(norm\) > 2:
            pos_violation = True

    if pos_violation:
        violations['position'] += 1
    elif any\('sub limit' in w for w in plan.warnings\):
        violations['sub_limit'] += 1

print\('Violations over 500 runs:', violations\)
